CQL Library: SharedResourceCreation
Define: EncounterClassHistory
Program: None
Measure group: None
Reporting frequency: None

define function EncounterClassHistory(classHistory List<FHIR.Encounter.ClassHistory>):
classHistory cH
return FHIR.Encounter.ClassHistory{
class: cH.class,
period: cH.period
}

